  "filing_type": "10-K",
  "fiscal_year": "2023",
  "risk_factors": [
    {
      "factor": "Class action lawsuit alleging Fair Lending Act violations and discriminatory lending practices with potential damages of $185 million",
      "category": "legal",
      "severity": "high",
      "evidence": "class action lawsuit filed in the United States District Court for the Southern District of New York alleging violations of the Fair Lending Act and discriminatory lending practices"
    },
    {
      "factor": "Adverse litigation outcomes could materially affect financial condition and results of operations",
      "category": "legal",
      "severity": "high",
      "evidence": "an adverse outcome could have a material adverse effect on our financial condition and results of operations"
    },
    {
      "factor": "Heightened regulatory scrutiny could result in additional enforcement actions, operational restrictions, or monetary penalties",
      "category": "regulatory",
      "severity": "medium",
      "evidence": "heightened scrutiny from federal banking regulators could result in additional enforcement actions, operational restrictions, or monetary penalties"
    },
    {
      "factor": "Legal and regulatory proceedings could materially impact reputation and competitive position",
      "category": "legal",
      "severity": "medium",
      "evidence": "unfavorable resolutions could materially impact our reputation, competitive position, and financial performance"
    }
  ],
  "material_events": [
    {
      "event": "Class action lawsuit filed alleging Fair Lending Act violations and discriminatory lending practices",
      "date": "2023-03-15",
      "impact": "negative",
      "details": "Lawsuit filed in US District Court for Southern District of New York seeking $185 million in compensatory damages plus punitive damages and injunctive relief for alleged discriminatory mortgage origination practices between 2019 and 2022"
    },
    {
      "event": "Settlement agreement reached with Consumer Financial Protection Bureau regarding improper overdraft fee practices",
      "date": "2023-09-08",
      "impact": "negative",
      "details": "Company agreed to pay $42 million civil monetary penalty and $28 million in customer restitution, recording total liability of $70 million in Q3 2023"
    }
  ],
  "financial_obligations": [
    {
      "obligation": "CFPB civil monetary penalty",
      "amount": "$42M",
      "deadline": "2024-12-31",
      "category": "legal"
    },
    {
      "obligation": "Customer restitution for overdraft fee practices",
      "amount": "$28M",
      "deadline": "2024-12-31",
      "category": "legal"
    }
  ],
  "summary": "United Federal Bancorp faces significant legal exposure from a $185 million class action lawsuit alleging Fair Lending Act violations and discriminatory lending practices. The Company has also settled with the CFPB for $70 million related to improper overdraft fees, with payments due by December 31, 2024. Ongoing regulatory scrutiny presents additional risks of enforcement actions and reputational harm."
}

